const config = $('Configuration (EDIT ME)').first().json;
const rows = $('Get Ready Rows').all();
const channels = $input.first().json.data || [];
const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');

if (!rows.length) return [];

const find = (token) => {
  const t = String(token).trim().toLowerCase().replace(/^@/, '');
  return channels.find((c) => c.id === token.trim()
    || String(c.username || '').toLowerCase() === t
    || String(c.display_name || '').toLowerCase() === t);
};

const out = [];
for (const row of rows) {
  const r = row.json;
  const tokens = String(r.Channels || '').split(',').map((s) => s.trim()).filter(Boolean);
  for (const token of tokens) {
    const channel = find(token);
    out.push({ json: {
      rowNumber: r.row_number,
      channelToken: token,
      channelId: channel ? channel.id : null,
      platform: channel ? channel.platform : null,
      error: channel ? null : `Channel "${token}" not found in PostStack`,
      text: r.Text || '',
      hashtags: r.Hashtags || '',
      imageUrl: r.ImageURL || '',
      date: r.Date || '',
      createUrl: `${baseUrl}/api/v1/posts`,
    } });
  }
}
return out;

const config = $('Configuration (EDIT ME)').first().json;
const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');
const plans = $('Build Posts per Channel').all();

return $input.all().map((item, i) => {
  const plan = plans[i].json;
  const res = item.json;
  const created = res.statusCode >= 200 && res.statusCode < 300 && res.body && res.body.data;
  const postId = created ? res.body.data.id : null;
  const error = plan.error || (created ? null : `create failed: HTTP ${res.statusCode} ${JSON.stringify(res.body && res.body.error || '').slice(0, 200)}`);
  const when = plan.date && new Date(plan.date) > new Date() ? new Date(plan.date).toISOString() : 'now';
  return { json: {
    rowNumber: plan.rowNumber,
    channelId: plan.channelId,
    postId,
    error,
    when,
    publishUrl: postId ? `${baseUrl}/api/v1/posts/${postId}/publish` : null,
  } };
});

const preps = $('Prepare Publish').all();
const rows = new Map();

$input.all().forEach((item, i) => {
  const prep = preps[i].json;
  const res = item.json;
  const published = prep.postId && res.statusCode >= 200 && res.statusCode < 300;
  const error = prep.error || (published ? null : `publish failed: HTTP ${res.statusCode} ${JSON.stringify(res.body && res.body.error || '').slice(0, 200)}`);
  const agg = rows.get(prep.rowNumber) || { postIds: [], errors: [] };
  if (published) agg.postIds.push(prep.postId);
  if (error) agg.errors.push(error);
  rows.set(prep.rowNumber, agg);
});

return [...rows.entries()].map(([rowNumber, agg]) => ({ json: {
  row_number: rowNumber,
  Status: agg.errors.length ? 'error' : 'scheduled',
  PostIDs: agg.postIds.join(', '),
  Error: agg.errors.join(' | '),
} }));
